class Solution {
public:
    vector<string> removeSubfolders(vector<string>& folder) {
        set<string> seen;
        vector<string> result;
        for (string& path : folder) {
            string parent = path.substr(0, path.find_last_of('/'));
            if (seen.count(parent) == 0) {
                seen.insert(path);
                result.push_back(path);
            }
        }
        return result;
    }
};
